class NoDepartmentSelectedError(ValueError):
    """Raised when an announcement is published with no departments."""


class PermissionDeniedError(PermissionError):
    """Raised when a non-system-admin tries to publish."""


class Announcement:
    """Value object / entity returned after a successful publish."""

    def __init__(self, announcement_id: str, title: str, body: str, departments: list[str]):
        if not departments:
            raise NoDepartmentSelectedError("At least one department must be selected.")
        self.announcement_id = announcement_id
        self.title = title
        self.body = body
        self.departments = list(departments)
        self.published = True

    def __eq__(self, other):
        return isinstance(other, Announcement) and self.announcement_id == other.announcement_id

    def __hash__(self):
        return hash(self.announcement_id)


class AnnouncementRepository:
    """Simple in-memory repository used by the fake service."""

    def __init__(self):
        self._store: dict[str, Announcement] = {}

    def exists(self, announcement_id: str) -> bool:
        return announcement_id in self._store

    def save(self, announcement: Announcement) -> None:
        self._store[announcement.announcement_id] = announcement

    def find_by_id(self, announcement_id: str) -> Announcement | None:
        return self._store.get(announcement_id)

    def find_by_departments(self, departments: list[str]) -> list[Announcement]:
        result = []
        for ann in self._store.values():
            if any(d in ann.departments for d in departments):
                result.append(ann)
        return result

    def count(self) -> int:
        return len(self._store)


